throw new Error('Backbrief skeleton not deployed — run: node plugin/scripts/deploy-pipeline.js --import');

// V1.4 — Graceful fallback when Download .vtt fails (4xx/5xx after retries, neverError=true).
// Without this, an expired transcript_download_url (24h Zoom limit) would crash the exec
// and orphan the Phase 1 Slack post forever.
const meta = { ...$('Recording state lookup').first().json };
delete meta.transcript_access_token;
delete meta.transcript_download_url;

const resp = $input.first().json || {};
const statusCode = resp.statusCode || resp.status || (resp.body ? 200 : null);
const bodyText   = typeof resp.body === 'string' ? resp.body :
                   typeof resp.data === 'string' ? resp.data :
                   typeof resp === 'string'      ? resp :
                   '';
const okStatus = statusCode === null || (statusCode >= 200 && statusCode < 300);
const hasText  = bodyText && bodyText.length > 0 && bodyText.includes('WEBVTT');

if (!okStatus || !hasText) {
  console.log(`[attach-vtt] download failed: status=${statusCode}, body length=${bodyText.length}, hasWEBVTT=${hasText}. Continuing with empty transcript.`);
  return [{ json: {
    ...meta,
    vtt_content                : '',
    vtt_download_failed        : true,
    vtt_download_failed_status : statusCode || 'unknown',
  } }];
}
return [{ json: { ...meta, vtt_content: bodyText } }];

